// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract GrandGooseMansion {
    address private immutable _owner;
    uint256 public supply = 0;
    uint256 public cost = 1 gwei; // Use a standard unit like gwei instead of ether
    uint256 public maxSupply = 10000;
    uint256 public preSaleWalletLimit = 10;
    mapping(address => uint256) public preSaleWalletMinted;
    enum SaleStatus { Paused, Presale, PublicSale }
    SaleStatus public currentSaleStatus = SaleStatus.Paused;
    mapping(address => bool) public whitelist;
    bool private _notEntered;

    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);
    event Minted(address indexed minter, uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == _owner, "Not owner");
        _;
    }

    modifier noReentrancy() {
        require(!_notEntered, "No reentrancy");
        _notEntered = true;
        _;
        _notEntered = false;
    }

    constructor() {
        _owner = msg.sender;
    }

    function isWhitelisted(address user) public view returns (bool) {
        return whitelist[user];
    }

    function whitelistUser(address user, bool status) public onlyOwner {
        whitelist[user] = status;
    }

    function startPresale() public onlyOwner {
        require(currentSaleStatus == SaleStatus.Paused, "Already started");
        currentSaleStatus = SaleStatus.Presale;
    }

    function startPublicSale() public onlyOwner {
        require(currentSaleStatus == SaleStatus.Presale, "Already started");
        currentSaleStatus = SaleStatus.PublicSale;
    }

    function setCost(uint256 newCost) public onlyOwner {
        cost = newCost;
    }

    function mintTokenWhitelisted(uint256 amount) public payable noReentrancy {
        require(currentSaleStatus == SaleStatus.Presale, "Not in presale");
        require(whitelist[msg.sender], "Not whitelisted");
        require(amount > 0, "Amount must be greater than 0");
        require(supply + amount <= maxSupply, "Exceeds max supply");
        require(preSaleWalletMinted[msg.sender] + amount <= preSaleWalletLimit, "Exceeds wallet limit");
        require(msg.value >= cost * amount, "Insufficient funds");

        preSaleWalletMinted[msg.sender] += amount;
        supply += amount;
        emit Minted(msg.sender, amount);
    }

    function mintTokenPublic(uint256 amount) public payable noReentrancy {
        require(currentSaleStatus == SaleStatus.PublicSale, "Not in public sale");
        require(amount > 0, "Amount must be greater than 0");
        require(supply + amount <= maxSupply, "Exceeds max supply");
        require(msg.value >= cost * amount, "Insufficient funds");

        supply += amount;
        emit Minted(msg.sender, amount);
    }

    receive() external payable {}

    // Getter for preSaleWalletMinted to optimize gas usage
    function getPreSaleWalletMinted(address account) public view returns (uint256) {
        return preSaleWalletMinted[account];
    }
}
